<?phpnamespace App\Controller;use App\Entity\Cercle;use App\Entity\Region;use App\Entity\SysAdminOperation;use App\Form\CercleType;use App\Repository\CercleRepository;use App\Repository\QuartierRepository;use DateTime;use DateTimeZone;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class CercleController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/cercles", name="cercle_index", methods={"GET"})     * @param CercleRepository $cercleRepository     * @return Response     */    public function index(CercleRepository $cercleRepository): Response    {        return $this->render('cercle/index.html.twig', [            'cercles' => $cercleRepository->findAll(),        ]);    }        /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/cercles/new", name="cercle_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws Exception     */    public function new(Request $request): Response    {        $cercle = new Cercle();        $form = $this->createForm(CercleType::class, $cercle);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($cercle);            $entityManager->flush();            $this->addFlash('success', 'Le cercle a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setDescription('Enregistrement du cercle')                ->setKohUtilisateur($this->getUser())                ->setUserAffected($cercle->getName())                ->setUpdatedAt(new DateTime('now', new DateTimeZone('GMT')));            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('cercle_index');        }        return $this->render('cercle/new.html.twig', [            'cercle' => $cercle,            'form' => $form->createView(),        ]);    }    /**     * @Route("/super-admin/cercles/{id}", name="cercle_show", methods={"GET"})     * @param Cercle $cercle     * @return Response     */    public function show(Cercle $cercle): Response    {        return $this->render('cercle/show.html.twig', [            'cercle' => $cercle,        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/cercles/{id}/edit", name="cercle_edit", methods={"GET","POST"})     * @param Request $request     * @param Cercle $cercle     * @return Response     * @throws Exception     */    public function edit(Request $request, Cercle $cercle): Response    {        $form = $this->createForm(CercleType::class, $cercle);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le cercle a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification de cercle')                ->setUserAffected($cercle->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('cercle_index');        }        return $this->render('cercle/edit.html.twig', [            'cercle' => $cercle,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/cercles/{id}", name="cercle_delete", methods={"DELETE"})     * @param Request $request     * @param Cercle $cercle     * @return Response     * @throws Exception     */    public function delete(Request $request, Cercle $cercle): Response    {        if ($this->isCsrfTokenValid('delete' . $cercle->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($cercle);            $entityManager->flush();            $this->addFlash('success', 'Le cercle a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression de cercle')                ->setUserAffected($cercle->getName());            $this->getDoctrine()->getManager()->persist($sysOp);            $this->getDoctrine()->getManager()->flush();            return $this->redirectToRoute('region_index');        }        return $this->redirectToRoute('cercle_index');    }    /**     * @Route("/cercle/region_by_cercle/{id}")     * @param Region $region     * @return JsonResponse     */    public function getCercleByRegion(Region $region): JsonResponse    {        $cercles = $region->getCercles();        $array_cercles = array();        foreach ($cercles as $cercle) {            $c = array(                'id' => $cercle->getId(),                'libelle' => $cercle->getName()            );            $array_cercles[] = $c;        }        return new JsonResponse($array_cercles, 200);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/quartiers", name="quartiers_index", methods={"GET"})     * @param QuartierRepository $quartierRepository     * @return Response     */    public function indexQuartier(QuartierRepository $quartierRepository): Response    {        $quarties = $quartierRepository->findAll();        foreach ($quarties as $q) {            if ($q->getCommune() == null) {                dd($q);            }        }        return $this->render('cercle/index_quartier.html.twig', [            'quartiers' => $quartierRepository->findAll()        ]);    }    /**     * @Route("/quartiers/quartier_by_cercle_id/{id}")     * @param Cercle $cercle     * @param QuartierRepository $quartierRepository     * @return JsonResponse     */    public function getQuartierByCercleId(Cercle $cercle, QuartierRepository $quartierRepository): JsonResponse    {        $quartiers = $quartierRepository->getQuartierByCercleId($cercle->getId());        $quartiersArray = array();        foreach ($quartiers as $quartier) {            $q = array(                'id' => $quartier->getId(),                'libelle' => $quartier->getName()            );            $quartiersArray[] = $q;        }        return new JsonResponse($quartiersArray, 200);    }}